3. Métodos Auxiliares Privados
El script incluye varios métodos privados (prefijados con _) que realizan tareas específicas de validación, normalización y gestión de archivos.
    def _validar_directorio_repos(self):
        if not self.repos_path.exists():
            raise FileNotFoundError(
                f"El directorio de repositorios no existe: {self.repos_path}"
            )

        if not self.repos_path.is_dir():
            raise NotADirectoryError(
                f"La ruta de repositorios no es un directorio: {self.repos_path}"
            )

    def _resolver_syft(self) -&gt; str:
        ruta_syft = shutil.which(self.syft_bin)
        if not ruta_syft:
            raise RuntimeError(MENSAJE_SYFT_NO_INSTALADO)

        return ruta_syft

    def _construir_comando_syft(self, ruta_repo: Path) -&gt; list[str]:
        ruta_syft = self.syft_path or self._resolver_syft()
        return [ruta_syft, f"dir:{ruta_repo}", "-o", FORMATO_SALIDA_SYFT]

    def _normalizar_sbom_json(self, salida_cruda: str) -&gt; str:
        """Limpia ruido accidental y reserializa el resultado como JSON valido."""
        if not salida_cruda or not salida_cruda.strip():
            return ""

        texto_limpio = PATRON_ANSI.sub("", salida_cruda).replace("\ufeff", "").strip()
        candidatos = [texto_limpio]

        inicio_objeto = texto_limpio.find("{")
        fin_objeto = texto_limpio.rfind("}")
        if inicio_objeto != -1 and fin_objeto != -1 and inicio_objeto &lt; fin_objeto:
            candidatos.append(texto_limpio[inicio_objeto : fin_objeto + 1])

        inicio_lista = texto_limpio.find("[")
        fin_lista = texto_limpio.rfind("]")
        if inicio_lista != -1 and fin_lista != -1 and inicio_lista &lt; fin_lista:
            candidatos.append(texto_limpio[inicio_lista : fin_lista + 1])

        for candidato in candidatos:
            try:
                contenido = json.loads(candidato)
            except json.JSONDecodeError:
                continue

            return json.dumps(contenido, ensure_ascii=False, indent=2)

        raise RuntimeError("Syft devolvio una salida que no pudo normalizarse a JSON valido.")

    def _eliminar_archivos_parciales(self, repo_name: str):
        ruta_salida = self.output_path / f"{repo_name}{SUFIJO_SBOM}"
        if ruta_salida.exists():
            ruta_salida.unlink()

    def _eliminar_archivos_legados(self, repo_name: str):
        for sufijo in SUFIJOS_LEGADOS:
            ruta_salida = self.output_path / f"{repo_name}{sufijo}"
            if ruta_salida.exists():
                ruta_salida.unlink()
                LOGGER.info("Archivo legado eliminado: %s", ruta_salida)

Explicación del Código

Código Completo
let classifier;

// Array containing the 18 words of SpeechCommands18w
let words = [
    "zero", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine",
    "up", "down", "left", "right", "go", "stop", "yes", "no"
];

// Variable for displaying the results on the canvas
let predictedWord = "";

function preload() {
    // Options for the SpeechCommands18w model
    let options = { probabilityThreshold: 0.7 };
    // Load SpeechCommands18w sound classifier model
    classifier = ml5.soundClassifier("SpeechCommands18w", options);
}

function setup() {
    createCanvas(650, 450);
    // Classify the sound from microphone in real time
    classifier.classifyStart(gotResult);
}

function draw() {
    background(250);
    // Call function for displaying background words
    displayWords();

    // Once the model outputs results start displaying the predicted word
    if (predictedWord !== "") {
        fill(211, 107, 255);
        textAlign(CENTER, CENTER);
        textSize(64);
        text(predictedWord, width / 2, 90);
    }
}

// Function to display the 18 words on the canvas
function displayWords() {
    textAlign(CENTER, CENTER);
    textSize(32);
    fill(96);
    text("Say one of these words!", width / 2, 40);

    let x = 125;
    let y = 150;
    // Words appear in 3 columns of 6 rows
    for (let i = 0; i &lt; words.length; i++) {
        fill(158);
        text(words[i], x, y);
        y += 50;
        if ((i + 1) % 6 === 0) {
            x += 200;
            y = 150;
        }
    }
}

// A function to run when we get any errors and the results
function gotResult(results) {
    // The results are in an array ordered by confidence
    console.log(results);
    // Load the first label to the text variable
    if (results && results.length &gt; 0) {
        predictedWord = results[0].label;
    }
}


1. Declaración de Variables
Primero, declaramos las variables que necesitaremos:
let classifier;
let words = [
    "zero", "one", "two", "three", "four", "five", "six", "seven", "eight", "nine",
    "up", "down", "left", "right", "go", "stop", "yes", "no"
];
let predictedWord = "";

classifier: Almacenará el modelo SpeechCommands18w de ml5.js
words: Array con las 18 palabras que el modelo puede reconocer
predictedWord: Guardará la última palabra detectada por el modelo



2. Carga del Modelo (preload)
La función preload() carga el clasificador de sonido antes de iniciar:
function preload() {
    let options = { probabilityThreshold: 0.7 };
    classifier = ml5.soundClassifier("SpeechCommands18w", options);
}

probabilityThreshold: 0.7: Solo acepta predicciones con 70% o más de confianza
ml5.soundClassifier("SpeechCommands18w"): Carga el modelo pre-entrenado con 18 comandos
Esta función garantiza que el modelo esté listo antes de setup()



3. Configuración e Inicio de Clasificación (setup)
La función setup() configura el canvas e inicia la clasificación continua:
function setup() {
    createCanvas(650, 450);
    classifier.classifyStart(gotResult);
}

createCanvas(650, 450): Crea el lienzo para mostrar las palabras
classifyStart(gotResult): Inicia la clasificación continua del audio del micrófono
Cada vez que detecta un sonido, llama a gotResult() con los resultados



4. Visualización (draw)
La función draw() se ejecuta continuamente para mostrar la interfaz:
function draw() {
    background(250);
    displayWords();

    if (predictedWord !== "") {
        fill(211, 107, 255);
        textAlign(CENTER, CENTER);
        textSize(64);
        text(predictedWord, width / 2, 90);
    }
}

background(250): Limpia el canvas con un fondo gris claro
displayWords(): Muestra las 18 palabras disponibles
text(predictedWord, ...): Muestra en grande la palabra detectada en color morado



5. Mostrar Palabras Disponibles (displayWords)
Esta función dibuja todas las palabras que el usuario puede decir:
function displayWords() {
    textAlign(CENTER, CENTER);
    textSize(32);
    fill(96);
    text("Say one of these words!", width / 2, 40);

    let x = 125;
    let y = 150;
    for (let i = 0; i &lt; words.length; i++) {
        fill(158);
        text(words[i], x, y);
        y += 50;
        if ((i + 1) % 6 === 0) {
            x += 200;
            y = 150;
        }
    }
}

Organiza las 18 palabras en 3 columnas de 6 filas
(i + 1) % 6 === 0: Detecta cuando completar una columna
Mueve x a la derecha y resetea y al iniciar nueva columna



6. Procesamiento de Resultados (gotResult)
Esta función recibe las predicciones del clasificador:
function gotResult(results) {
    console.log(results);
    if (results && results.length &gt; 0) {
        predictedWord = results[0].label;
    }
}

results: Array ordenado por nivel de confianza
results[0].label: La palabra con mayor probabilidad
Se actualiza predictedWord que se muestra en draw()
Esta función se llama automáticamente cada vez que hay una nueva predicción

